// // This ADC converts an 8-bit analog signal to a 3-bit digital output by dividing the input into ranges: 255-171 (000), 170-86 (001), 85-0 (010)
module adc_8bit (  
    input [7:0] analog_in,  
    output reg [2:0] digital_out  
);  

always @(*) begin  
    if (analog_in <= 85)  
        digital_out = 3'b000;  
    else if (analog_in <= 170)  
        digital_out = 3'b001;  
    else  
        digital_out = 3'b010;  
end  
endmodule
